// All rows from the Postgres node
const rows = $items().map(item => item.json);

// Get period from Period Start node (real dates)
const periodStart = $('Read System State').first().json.period_start;
const periodEnd = $('Read System State').first().json.period_end;

// Get topic from first item (all items should have the same topic)
const topic = rows.length > 0 ? rows[0].topic : 'General';

// Build the payload for Gemini
const payload = {
  topic: topic,  // ← Add topic at top level
  audience_profile: 'HR and business managers, non-technical, Italy-based but English-speaking',
  period: {
    start: periodStart,
    end: periodEnd,
  },
  items: rows.map(r => ({
    enriched_id: r.enriched_id,
    item_id: r.item_id,
    source_id: r.source_id,
    topic: r.topic,  // ← Include topic in each item too
    title: r.title,
    url: r.url,
    published_at: r.published_at,
    language: r.language,
    category: r.category,
    tags: r.tags,
    short_summary: r.short_summary,
    detailed_summary: r.detailed_summary,
    importance_score: r.importance_score,
    virality_score: r.virality_score,
  })),
};

// Return a single item with this JSON
return [{ json: payload }];

// Universal LLM JSON parser (Claude + Gemini compatible)
const inputData = $input.first().json || {};
let parsedData = {};
let jsonText = '';

try {
  // Extract text from different LLM response structures

  // Claude format: content[0].text
  if (inputData.content && Array.isArray(inputData.content)) {
    jsonText = inputData.content[0]?.text || '';
  }
  // Gemini format: text or content (string)
  else {
    jsonText = inputData.text || 
               inputData.content || 
               inputData.message?.content?.[0]?.text || 
               '';
  }

  // Remove markdown code blocks - multiple approaches
  // 1. Try regex first
  let jsonMatch = jsonText.match(/```(?:json)?\s*([\s\S]*?)\s*```/);
  if (jsonMatch) {
    jsonText = jsonMatch[1];
  } else {
    // 2. Manual cleanup if regex fails
    jsonText = jsonText
      .replace(/^```json\s*/i, '')  // Remove opening ```json
      .replace(/^```\s*/, '')        // Remove opening ```
      .replace(/\s*```$/, '');       // Remove closing ```
  }

  // Clean up the text
  jsonText = jsonText.trim();

  // Parse the JSON
  parsedData = JSON.parse(jsonText);

} catch (error) {
  // Return detailed error for debugging
  const errorPos = error.message.match(/position (\d+)/)?.[1];

  return [{
    json: {
      error: 'JSON PARSING FAILED',
      error_message: error.message,
      error_position: errorPos || 'unknown',
      raw_text_preview: jsonText.substring(0, 500),
      raw_text_around_error: errorPos 
        ? jsonText.substring(Math.max(0, parseInt(errorPos) - 100), parseInt(errorPos) + 100)
        : jsonText.substring(0, 200)
    }
  }];
}

// Return in n8n format
return [{
  json: parsedData
}];

const periodData = $('Read System State').first().json;

// Check which path we came from
const existingDigest = $('Check Existing Digest').first().json;
const hasExisting = existingDigest && existingDigest.id !== null;

// Check if we created a new digest (came from TRUE branch of IF)
let digestId = null;
let dominantTopic = null;
let event = 'no_items_to_digest';

if (hasExisting) {
  event = 'digest_already_exists';
  digestId = existingDigest.id;
} else {
  try {
    const insertNode = $('Insert Into digests Table').all();
    if (insertNode.length > 0 && insertNode[0].json.id) {
      event = 'digest_created';
      digestId = insertNode[0].json.id;
      dominantTopic = insertNode[0].json.dominant_topic;
    }
  } catch (error) {
    // Insert didn't run (no items path)
  }
}

return [{
  json: {
    topic: 'unknown',
    workflow_id: 3,
    event: event,
    status: 'success',
    details: {
      period_start: periodData.period_start,
      period_end: periodData.period_end,
      digest_id: digestId,
      dominant_topic: dominantTopic
    }
  }
}];

